import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ===== Quote: base premiums =====
  it.todo("empty item list yields premium of 5 G (processing fee only)");
  it.todo("single plain sword yields 100 G base + 10 G first insurance + 5 G fee = 115 G");
  it.todo("single plain amulet yields 60 + 6 + 5 = 71 G");
  it.todo("single plain staff yields 80 + 8 + 5 = 93 G");
  it.todo("single plain potion yields 40 + 4 + 5 = 49 G");

  // ===== Quote: components =====
  it.todo("single rune: 25 G base + 2.5 first insurance + 5 fee = 33 G (rounded up)");
  it.todo("2 runes: 50 + 5 + 5 = 60 G");
  it.todo("3 runes form a block: 60 G base + 6 + 5 = 71 G");
  it.todo("4 runes: 100 + 10 + 5 = 115 G (no block, requires exactly 3)");
  it.todo("7 runes: 175 + 17.5 + 5 = 198 G (rounded up)");
  it.todo("2 runes + 1 moonstone: 75 G base (no block, different types)");
  it.todo("3 runes + 3 moonstones: 120 G base (two separate blocks)");

  // ===== Quote: per-item modifiers =====
  it.todo("cursed sword adds 50% surcharge to that item's base premium");
  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge");
  it.todo("enchantment 4 does NOT trigger high-enchantment surcharge");
  it.todo("cursed AND enchantment 5 sword: both surcharges apply");

  // ===== Quote: policy-wide modifiers =====
  it.todo("long-standing customer (2 years) gets 20% loyalty discount on policy base");
  it.todo("first quote applies +10% first insurance per item base");
  it.todo("second quote applies -15% follow-up contract discount on policy base");

  // ===== Quote: rounding =====
  it.todo("premium rounded up in MHPCO favor (197.5 → 198)");

  // ===== Quote: multi-item policy scope =====
  it.todo("cursed sword + plain amulet, newcomer: 210 G before fee → 215 G total");

  // ===== Quote: integration examples =====
  it.todo("newcomer with cursed sword (steel, ench 3): 165 G");
  it.todo("3-year customer's second contract, cursed sword (ench 7): 160 G");

  // ===== Quote: errors =====
  it.todo("unknown item type causes scenario to throw error");

  // ===== Claim: base reimbursement =====
  it.todo("regular sword damage 500 G → payout 400 G");
  it.todo("rune damage 200 G → payout 100 G");
  it.todo("enchantment 8 sword damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full, then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");

  // ===== Claim: multiple damages =====
  it.todo("dragon attack: sword 500 G + amulet 300 G → payout 600 G (deductible per item)");
  it.todo("two swords insured, both damaged: each gets own deductible");

  // ===== Claim: rounding =====
  it.todo("payout rounded down in MHPCO favor (350.5 → 350)");

  // ===== Claim: errors =====
  it.todo("damage references item not in policy → throws");
  it.todo("more damages of a type than items insured → throws");
  it.todo("negative damage amount → throws");
});

