type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const MAIN_BASE: Record<string, number> = { sword: 100, amulet: 60, staff: 80, potion: 40 };
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_UNIT_BASE = 25;
const COMPONENT_BLOCK_BASE = 60;

const itemBaseFractions = (items: Item[]): number => {
  let total = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += MAIN_BASE[item.type] ?? 0;
    }
  }
  for (const count of Object.values(componentCounts)) {
    if (count === 3) {
      total += COMPONENT_BLOCK_BASE;
    } else {
      total += count * COMPONENT_UNIT_BASE;
    }
  }
  return total;
};

export const runScenario = (input: Scenario): { results: Array<{ premium: number }> } => {
  const results = input.steps.map((step) => {
    const itemsBase = itemBaseFractions(step.items);
    const firstInsurance = itemsBase * 0.1;
    return { premium: Math.ceil(itemsBase + firstInsurance + 5) };
  });
  return { results };
};

